// show submenu
function expandAllOpen() {
  $('div.accordion div').slideDown('fast'); // slidedown all divs
  $(".open-close").html('-'); //change all spans - this might need chaning at some point
  $('#expandall').html('Hide every month') //change innerHTML
}
// hide submenu
function expandAllClose() {
  $(".open-close").html('+'); //change spans
  $('div.accordion div').slideUp('fast'); //slide up all divs
  $('#expandall').html('View every month') //change innerHTML
} 
          
          //EXPAND ALL
$('#expandall').toggle(function (event) { //#expand is a toggle button
  event.preventDefault(); //prevent follow link
  expandAllOpen();
}, //end of this toggle
function (event) { //new toggle 
  event.preventDefault(); //prevent follow link
  expandAllClose();
});
          if ($("div.accordion div:visible").length === 0) {
  $('#expandall').click();
}
          //Print-cal
          $('#print-cal-btn').click(function (event) { // on click
                      expandAllOpen();
                      setTimeout(function(){
                                              var prtTitle = document.getElementById('print-cal-title');
                                              var prtPre = document.getElementById('print-cal-pre');
                                              var prtContent = document.getElementById('print-cal');
                                              var WinPrint = window.open('', '', 'left=0,top=0,width=800,height=900,toolbar=0,scrollbars=0,status=0');
                                              WinPrint.document.write('<html><head><title>'+prtTitle.innerHTML+'</title><link rel="stylesheet" type="text/css" href="/_css/print-v1.css"></head><body>');
                                              WinPrint.document.write('<h1>'+prtTitle.innerHTML+'</h1>');
                                              WinPrint.document.write(prtPre.innerHTML);
                                              WinPrint.document.write(prtContent.innerHTML);
                                              WinPrint.document.write('</body></html>');
                                              WinPrint.document.close();
                                              WinPrint.focus();
                                              setTimeout(function(){
                                                          WinPrint.print();
                                                          WinPrint.close();
                                              }, 100);
                      }, 200);
});

